import React, { useState, useEffect } from 'react';
import { db } from '../firebase/config';
import { collection, query, where, orderBy, onSnapshot, Timestamp, doc, updateDoc } from 'firebase/firestore';
import Card from './Card';
import { AlertTriangle, CalendarDays, Tag, Scale, Package, Gift, Trash2, TrendingUp } from 'lucide-react';

export default function ProductDecisions() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const today = new Date();
    const threeDaysFromNow = new Date();
    threeDaysFromNow.setDate(today.getDate() + 3);

    // Fetch products expiring within 3 days (and not yet destroyed)
    const q = query(
      collection(db, 'products'),
      where('expiryDate', '<=', Timestamp.fromDate(threeDaysFromNow)),
      where('expiryDate', '>=', Timestamp.fromDate(today)), // Only show future or today's expiry
      where('decisionStatus', '!=', 'destroyed'), // Don't show already destroyed products
      orderBy('decisionStatus', 'asc'), // Order to show 'to_handle' first
      orderBy('expiryDate', 'asc')
    );

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedProducts = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data(),
        expiryDate: doc.data().expiryDate?.toDate().toLocaleDateString('fr-FR'),
      }));
      setProducts(fetchedProducts);
      setLoading(false);
    }, (err) => {
      console.error("Error fetching product decisions:", err);
      setError("Erreur lors du chargement des décisions produits.");
      setLoading(false);
    });

    return () => unsubscribe(); // Cleanup the listener
  }, []);

  const handleDecision = async (productId, decision) => {
    try {
      const productRef = doc(db, 'products', productId);
      await updateDoc(productRef, {
        decisionStatus: decision,
        lastDecisionDate: Timestamp.now(),
      });
      // setFeedback(`Décision "${decision}" appliquée avec succès.`); // Removed to prevent too many re-renders
    } catch (err) {
      console.error("Error updating decision status:", err);
      // setFeedback("Erreur lors de l'application de la décision."); // Removed to prevent too many re-renders
    }
  };

  const getDaysUntilExpiry = (expiryDateString) => {
    const today = new Date();
    const expiry = new Date(expiryDateString.split('/').reverse().join('-')); // Convert DD/MM/YYYY to YYYY-MM-DD
    const diffTime = expiry.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    return diffDays;
  };

  if (loading) {
    return (
      <Card title="Décisions Produits" titleIcon={<AlertTriangle />}>
        <p className="text-center text-gray-400">Chargement des produits...</p>
      </Card>
    );
  }

  if (error) {
    return (
      <Card title="Décisions Produits" titleIcon={<AlertTriangle />}>
        <p className="text-center text-red-500">{error}</p>
      </Card>
    );
  }

  return (
    <Card title="Décisions Produits" titleIcon={<AlertTriangle />}>
      {products.length === 0 ? (
        <p className="text-center text-gray-400">Aucun produit nécessitant une décision pour le moment.</p>
      ) : (
        <ul className="space-y-4">
          {products.map(product => {
            const daysLeft = getDaysUntilExpiry(product.expiryDate);
            return (
              <li key={product.id} className="bg-black/30 p-4 rounded-lg border border-gray-700">
                <div className="flex items-center justify-between mb-2">
                  <h3 className="text-mictlan-gold font-bold text-sm uppercase">{product.name}</h3>
                  <span className={`px-2 py-1 rounded-full text-xs font-semibold ${
                      daysLeft <= 0 ? 'bg-red-500/20 text-red-400' :
                      daysLeft <= 1 ? 'bg-orange-500/20 text-orange-400' :
                      'bg-yellow-500/20 text-yellow-400'
                    }`}
                  >
                    {daysLeft <= 0 ? 'Périmé !' : `Expire dans ${daysLeft} jour(s)`}
                  </span>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 text-gray-300 text-xs">
                  <p className="flex items-center"><CalendarDays size={12} className="mr-1 text-gray-500" /> Péremption: {product.expiryDate}</p>
                  <p className="flex items-center"><Scale size={12} className="mr-1 text-gray-500" /> Poids: {product.weight} {product.unit}</p>
                  <p className="flex items-center"><Package size={12} className="mr-1 text-gray-500" /> Quantité: {product.quantity}</p>
                  {product.category && <p className="flex items-center"><Tag size={12} className="mr-1 text-gray-500" /> Catégorie: {product.category}</p>}
                  {product.price && <p className="flex items-center"><ListFilter size={12} className="mr-1 text-gray-500" /> Prix: {product.price}€</p>}
                  {product.photos && product.photos.length > 0 && (
                    <div className="sm:col-span-2">
                      <img src={product.photos[0]} alt={product.name} className="mt-2 max-h-24 object-contain rounded" />
                    </div>
                  )}
                  <div className="sm:col-span-2 flex justify-end gap-2 mt-2">
                      <button 
                        onClick={() => handleDecision(product.id, 'promoted')}
                        className="px-3 py-1 bg-green-600/80 hover:bg-green-500 rounded-lg text-white text-xs flex items-center gap-1"
                        disabled={product.decisionStatus === 'promoted'}
                      >
                        <TrendingUp size={12} /> Promouvoir
                      </button>
                      <button 
                        onClick={() => handleDecision(product.id, 'donated')}
                        className="px-3 py-1 bg-blue-600/80 hover:bg-blue-500 rounded-lg text-white text-xs flex items-center gap-1"
                        disabled={product.decisionStatus === 'donated'}
                      >
                        <Gift size={12} /> Donner
                      </button>
                      <button 
                        onClick={() => handleDecision(product.id, 'destroyed')}
                        className="px-3 py-1 bg-red-600/80 hover:bg-red-500 rounded-lg text-white text-xs flex items-center gap-1"
                        disabled={product.decisionStatus === 'destroyed'}
                      >
                        <Trash2 size={12} /> Détruire
                      </button>
                  </div>
                  <p className="sm:col-span-2 mt-2 text-right text-gray-500 text-xs">
                    Statut: {product.decisionStatus.replace('_', ' ')}
                    {product.lastDecisionDate && ` (le ${product.lastDecisionDate?.toDate().toLocaleDateString('fr-FR')})`}
                  </p>
                </div>
              </li>
            );
          })}
        </ul>
      )}
    </Card>
  );
}

