import React, { useState, useEffect } from 'react';
import { db } from '../firebase/config';
import { collection, query, where, orderBy, onSnapshot, Timestamp } from 'firebase/firestore';
import Card from './Card';
import { Lightbulb, CalendarDays, Tag, Scale, Package } from 'lucide-react';

export default function ClientSuggestions() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [filterCategory, setFilterCategory] = useState('');
  const [availableCategories, setAvailableCategories] = useState([]);

  useEffect(() => {
    const today = new Date();
    const sevenDaysFromNow = new Date();
    sevenDaysFromNow.setDate(today.getDate() + 7);

    // Fetch products expiring within 7 days
    let q = query(
      collection(db, 'products'),
      where('expiryDate', '<=', Timestamp.fromDate(sevenDaysFromNow)),
      where('expiryDate', '>=', Timestamp.fromDate(today)), // Only show future or today's expiry
      where('decisionStatus', '!=', 'destroyed'), // Don't suggest destroyed products
      orderBy('decisionStatus', 'asc'), // Order to show 'to_handle' first, then 'promoted', 'donated', etc.
      orderBy('expiryDate', 'asc')
    );

    // Apply category filter if selected
    if (filterCategory) {
      q = query(q, where('category', '==', filterCategory));
    }

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedProducts = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data(),
        expiryDate: doc.data().expiryDate?.toDate().toLocaleDateString('fr-FR'),
      }));
      setProducts(fetchedProducts);
      setLoading(false);
    }, (err) => {
      console.error("Error fetching client suggestions products:", err);
      setError("Erreur lors du chargement des suggestions pour les clients.");
      setLoading(false);
    });

    // Fetch all unique categories for filtering
    const categoriesQuery = query(collection(db, 'products'), orderBy('category', 'asc'));
    const unsubscribeCategories = onSnapshot(categoriesQuery, (snapshot) => {
      const categories = new Set();
      snapshot.forEach(doc => {
        const data = doc.data();
        if (data.category) {
          categories.add(data.category);
        }
      });
      setAvailableCategories(['', ...Array.from(categories)]); // Add empty option for 'all'
    });

    return () => {
      unsubscribe();
      unsubscribeCategories();
    };
  }, [filterCategory]);

  if (loading) {
    return (
      <Card title="Suggestions Clients" titleIcon={<Lightbulb />}>
        <p className="text-center text-gray-400">Chargement des suggestions...</p>
      </Card>
    );
  }

  if (error) {
    return (
      <Card title="Suggestions Clients" titleIcon={<Lightbulb />}>
        <p className="text-center text-red-500">{error}</p>
      </Card>
    );
  }

  const getDaysUntilExpiry = (expiryDateString) => {
    const today = new Date();
    const expiry = new Date(expiryDateString.split('/').reverse().join('-')); // Convert DD/MM/YYYY to YYYY-MM-DD
    const diffTime = expiry.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    return diffDays;
  };

  return (
    <Card title="Suggestions Clients" titleIcon={<Lightbulb />}>
      <div className="mb-4">
        <label htmlFor="categoryFilter" className="block text-gray-400 text-xs mb-1">Filtrer par Catégorie:</label>
        <select
          id="categoryFilter"
          value={filterCategory}
          onChange={(e) => setFilterCategory(e.target.value)}
          className="w-full p-2 bg-black/40 text-white border border-gray-700 rounded focus:outline-none focus:ring-1 focus:ring-mictlan-gold text-xs"
        >
          {availableCategories.map(cat => (
            <option key={cat} value={cat}>{cat || 'Toutes les catégories'}</option>
          ))}
        </select>
      </div>

      {products.length === 0 ? (
        <p className="text-center text-gray-400">Aucune suggestion pour les clients en ce moment.</p>
      ) : (
        <ul className="space-y-4">
          {products.map(product => {
            const daysLeft = getDaysUntilExpiry(product.expiryDate);
            return (
              <li key={product.id} className="bg-black/30 p-4 rounded-lg border border-gray-700">
                <div className="flex items-center justify-between mb-2">
                  <h3 className="text-mictlan-gold font-bold text-sm uppercase">{product.name}</h3>
                  <span className={`px-2 py-1 rounded-full text-xs font-semibold ${
                      daysLeft <= 0 ? 'bg-red-500/20 text-red-400' :
                      daysLeft <= 3 ? 'bg-orange-500/20 text-orange-400' :
                      'bg-yellow-500/20 text-yellow-400'
                    }`}
                  >
                    {daysLeft <= 0 ? 'Périmé !' : `Expire dans ${daysLeft} jour(s)`}
                  </span>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 text-gray-300 text-xs">
                  <p className="flex items-center"><CalendarDays size={12} className="mr-1 text-gray-500" /> Péremption: {product.expiryDate}</p>
                  <p className="flex items-center"><Scale size={12} className="mr-1 text-gray-500" /> Poids: {product.weight} {product.unit}</p>
                  <p className="flex items-center"><Package size={12} className="mr-1 text-gray-500" /> Quantité: {product.quantity}</p>
                  {product.category && <p className="flex items-center"><Tag size={12} className="mr-1 text-gray-500" /> Catégorie: {product.category}</p>}
                  {product.price && <p className="flex items-center"><ListFilter size={12} className="mr-1 text-gray-500" /> Prix: {product.price}€</p>}
                  {product.photos && product.photos.length > 0 && (
                    <div className="sm:col-span-2">
                      <img src={product.photos[0]} alt={product.name} className="mt-2 max-h-24 object-contain rounded" />
                    </div>
                  )}
                  <div className="sm:col-span-2 flex justify-end gap-2 mt-2">
                      {/* Placeholder for reduction/grouped offer options */}
                      <button className="px-3 py-1 bg-blue-600/80 hover:bg-blue-500 rounded-lg text-white text-xs">Offre Spéciale</button>
                      <button className="px-3 py-1 bg-purple-600/80 hover:bg-purple-500 rounded-lg text-white text-xs">Pack Promo</button>
                  </div>
                </div>
              </li>
            );
          })}
        </ul>
      )}
    </Card>
  );
}

