import { db } from '../firebase/config';
import { collection, query, onSnapshot, Timestamp } from 'firebase/firestore';
import Card from './Card';
import { BarChart2 } from 'lucide-react';

export default function ProductReporting() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [report, setReport] = useState(null);

  useEffect(() => {
    const q = query(collection(db, 'products'));

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedProducts = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data(),
        expiryDate: doc.data().expiryDate?.toDate(), // Keep as Date object for calculations
      }));
      setProducts(fetchedProducts);
      setLoading(false);
    }, (err) => {
      console.error("Error fetching products for reporting:", err);
      setError("Erreur lors du chargement des produits pour le rapport.");
      setLoading(false);
    });

    return () => unsubscribe(); // Cleanup the listener
  }, []);

  useEffect(() => {
    if (products.length > 0) {
      generateReport(products);
    } else if (!loading) { // If no products and not loading, clear report
        setReport(null);
    }
  }, [products, loading]);

  const generateReport = (productList) => {
    const today = new Date();
    const threeDaysFromNow = new Date(today);
    threeDaysFromNow.setDate(today.getDate() + 3);
    const sevenDaysFromNow = new Date(today);
    sevenDaysFromNow.setDate(today.getDate() + 7);

    let totalProducts = productList.length;
    let byDecisionStatus = {};
    let byExpiryRange = {
      'expired': 0,
      '0-3_days': 0,
      '4-7_days': 0,
      '8+_days': 0,
    };
    let productsNeedingAttention = 0;

    productList.forEach(product => {
      // By Decision Status
      byDecisionStatus[product.decisionStatus] = (byDecisionStatus[product.decisionStatus] || 0) + 1;

      // By Expiry Range
      if (product.expiryDate) {
        if (product.expiryDate.getTime() < today.getTime()) {
          byExpiryRange['expired']++;
          if (product.decisionStatus === 'to_handle') {
            productsNeedingAttention++;
          }
        } else if (product.expiryDate.getTime() <= threeDaysFromNow.getTime()) {
          byExpiryRange['0-3_days']++;
          if (product.decisionStatus === 'to_handle') {
            productsNeedingAttention++;
          }
        } else if (product.expiryDate.getTime() <= sevenDaysFromNow.getTime()) {
          byExpiryRange['4-7_days']++;
          if (product.decisionStatus === 'to_handle') {
            productsNeedingAttention++;
          }
        } else {
          byExpiryRange['8+_days']++;
        }
      }
    });

    setReport({
      totalProducts,
      byDecisionStatus,
      byExpiryRange,
      productsNeedingAttention,
    });
  };

  if (loading) {
    return (
      <Card title="Rapport Produits" titleIcon={<BarChart2 />}>
        <p className="text-center text-gray-400">Génération du rapport...</p>
      </Card>
    );
  }

  if (error) {
    return (
      <Card title="Rapport Produits" titleIcon={<BarChart2 />}>
        <p className="text-center text-red-500">{error}</p>
      </Card>
    );
  }

  return (
    <Card title="Rapport Produits" titleIcon={<BarChart2 />}>
      {report ? (
        <div className="space-y-4 text-xs">
          <h3 className="text-white font-bold text-sm uppercase">Statistiques Générales</h3>
          <p>Total produits: <span className="text-mictlan-gold">{report.totalProducts}</span></p>
          <p>Produits nécessitant une décision: <span className="text-red-400 font-bold">{report.productsNeedingAttention}</span></p>

          <h3 className="text-white font-bold text-sm uppercase mt-6">Par Statut de Décision</h3>
          <ul className="list-disc list-inside ml-2">
            {Object.entries(report.byDecisionStatus).map(([status, count]) => (
              <li key={status}>{status.replace('_', ' ')}: <span className="text-mictlan-gold">{count}</span></li>
            ))}
          </ul>

          <h3 className="text-white font-bold text-sm uppercase mt-6">Par Date de Péremption</h3>
          <ul className="list-disc list-inside ml-2">
            <li>Périmés: <span className="text-red-400 font-bold">{report.byExpiryRange['expired']}</span></li>
            <li>Expire dans 0-3 jours: <span className="text-orange-400">{report.byExpiryRange['0-3_days']}</span></li>
            <li>Expire dans 4-7 jours: <span className="text-yellow-400">{report.byExpiryRange['4-7_days']}</span></li>
            <li>Expire dans 8+ jours: <span className="text-gray-400">{report.byExpiryRange['8+_days']}</span></li>
          </ul>
        </div>
      ) : (
        <p className="text-center text-gray-400">Aucun produit pour générer un rapport.</p>
      )}
    </Card>
  );
}

