const functions = require("firebase-functions");
const admin = require("firebase-admin");

// Initialize Firebase Admin SDK
// This assumes your Cloud Function environment has the necessary credentials (handled by Firebase automatically)
admin.initializeApp();

const db = admin.firestore();

// --- Helper function to check if user is admin ---
const isAuthenticatedAdmin = async (context) => {
  if (!context.auth) {
    throw new functions.https.HttpsError('unauthenticated', 'The function must be called while authenticated.');
  }

  const uid = context.auth.uid;
  const userDoc = await db.collection('users').doc(uid).get(); // Assuming 'users' collection stores user roles
  if (!userDoc.exists) {
    throw new functions.https.HttpsError('not-found', 'User data not found.');
  }
  const userData = userDoc.data();
  if (userData.role !== 'admin') {
    throw new functions.https.HttpsError('permission-denied', 'Only admin users can perform this action.');
  }
  return true;
};

// --- Populate Products Cloud Function ---
exports.populateProducts = functions.https.onCall(async (data, context) => {
  await isAuthenticatedAdmin(context); // Ensure only admin can call

  const productsRef = db.collection('products');
  const batch = db.batch();

  const now = new Date();
  const getDate = (daysOffset) => {
    const d = new Date(now);
    d.setDate(now.getDate() + daysOffset);
    return admin.firestore.Timestamp.fromDate(d);
  };

  const testProducts = [
    { name: 'Yaourt Grec Nature', weight: 150, unit: 'g', expiryDate: getDate(2), quantity: 5, category: 'Laitier', price: 1.20, photos: ['https://source.unsplash.com/random/100x100?yogurt'], decisionStatus: 'to_handle', creationDate: admin.firestore.Timestamp.fromDate(now) },
    { name: 'Salade Composée', weight: 300, unit: 'g', expiryDate: getDate(0), quantity: 2, category: 'Traiteur', price: 4.50, photos: ['https://source.unsplash.com/random/100x100?salad'], decisionStatus: 'to_handle', creationDate: admin.firestore.Timestamp.fromDate(now) },
    { name: 'Jus d'Orange Frais', weight: 1000, unit: 'ml', expiryDate: getDate(6), quantity: 1, category: 'Boissons', price: 3.00, photos: ['https://source.unsplash.com/random/100x100?orange-juice'], decisionStatus: 'to_handle', creationDate: admin.firestore.Timestamp.fromDate(now) },
    { name: 'Pain de Mie Complet', weight: 500, unit: 'g', expiryDate: getDate(10), quantity: 1, category: 'Boulangerie', price: 2.10, photos: ['https://source.unsplash.com/random/100x100?bread'], decisionStatus: 'to_handle', creationDate: admin.firestore.Timestamp.fromDate(now) },
    { name: 'Steak de Boeuf', weight: 200, unit: 'g', expiryDate: getDate(1), quantity: 3, category: 'Viande', price: 6.80, photos: ['https://source.unsplash.com/random/100x100?steak'], decisionStatus: 'to_handle', creationDate: admin.firestore.Timestamp.fromDate(now) },
    { name: 'Fromage de Chèvre', weight: 180, unit: 'g', expiryDate: getDate(-5), quantity: 1, category: 'Fromage', price: 5.20, photos: ['https://source.unsplash.com/random/100x100?goat-cheese'], decisionStatus: 'to_handle', creationDate: admin.firestore.Timestamp.fromDate(now) },
    { name: 'Tomates Cerises', weight: 250, unit: 'g', expiryDate: getDate(4), quantity: 1, category: 'Légumes', price: 2.80, photos: ['https://source.unsplash.com/random/100x100?cherry-tomatoes'], decisionStatus: 'to_handle', creationDate: admin.firestore.Timestamp.fromDate(now) },
    { name: 'Eau Minérale', weight: 1500, unit: 'ml', expiryDate: getDate(300), quantity: 6, category: 'Boissons', price: 0.80, photos: ['https://source.unsplash.com/random/100x100?water'], decisionStatus: 'to_handle', creationDate: admin.firestore.Timestamp.fromDate(now) },
    { name: 'Pommes Bio', weight: 1, unit: 'kg', expiryDate: getDate(8), quantity: 1, category: 'Fruits', price: 3.50, photos: ['https://source.unsplash.com/random/100x100?apples'], decisionStatus: 'to_handle', creationDate: admin.firestore.Timestamp.fromDate(now) },
    { name: 'Lait demi-écrémé', weight: 1000, unit: 'ml', expiryDate: getDate(5), quantity: 2, category: 'Laitier', price: 1.00, photos: ['https://source.unsplash.com/random/100x100?milk'], decisionStatus: 'to_handle', creationDate: admin.firestore.Timestamp.fromDate(now) },
    { name: 'Pâtes Fraîches', weight: 500, unit: 'g', expiryDate: getDate(1), quantity: 1, category: 'Pâtes', price: 2.20, photos: ['https://source.unsplash.com/random/100x100?pasta'], decisionStatus: 'to_handle', creationDate: admin.firestore.Timestamp.fromDate(now) },
    { name: 'Saumon Fumé', weight: 120, unit: 'g', expiryDate: getDate(-1), quantity: 1, category: 'Poisson', price: 7.90, photos: ['https://source.unsplash.com/random/100x100?salmon'], decisionStatus: 'to_handle', creationDate: admin.firestore.Timestamp.fromDate(now) },
    { name: 'Fromage à la Coupe', weight: 250, unit: 'g', expiryDate: getDate(2), quantity: 1, category: 'Fromage', price: 8.50, photos: ['https://source.unsplash.com/random/100x100?cheese'], decisionStatus: 'promoted', creationDate: admin.firestore.Timestamp.fromDate(now) },
    { name: 'Jambon Cuit Tranché', weight: 150, unit: 'g', expiryDate: getDate(0), quantity: 1, category: 'Charcuterie', price: 3.80, photos: ['https://source.unsplash.com/random/100x100?ham'], decisionStatus: 'donated', creationDate: admin.firestore.Timestamp.fromDate(now) },
  ];

  testProducts.forEach(product => {
    batch.add(productsRef, product);
  });

  await batch.commit();
  return { message: `Successfully added ${testProducts.length} test products.` };
});

// --- Clear Products Cloud Function ---
exports.clearProducts = functions.https.onCall(async (data, context) => {
  await isAuthenticatedAdmin(context); // Ensure only admin can call

  const productsRef = db.collection('products');
  const snapshot = await productsRef.get();

  if (snapshot.empty) {
    return { message: 'No documents found in "products" collection. Nothing to delete.' };
  }

  const batch = db.batch();
  snapshot.docs.forEach(doc => {
    batch.delete(doc.ref);
  });
  await batch.commit();
  return { message: `Successfully deleted ${snapshot.docs.length} documents from "products" collection.` };
});

