  const [isEmptying, setIsEmptying] = useState(false);
  const [isPopulatingProducts, setIsPopulatingProducts] = useState(false); // New state
  const [isClearingProducts, setIsClearingProducts] = useState(false);     // New state
  const [productFeedback, setProductFeedback] = useState('');              // New state for product actions

  const handleReset = async () => {
    setIsUpdating(true);
    try {
      await resetDatabase(tableCount);
    } catch {
      alert("Erreur lors de la mise à jour");
    } finally {
      setIsUpdating(false);
    }
  };

  const handleEmpty = async () => {
    if (!confirm("Êtes-vous sûr de vouloir vider complètement la base de données ? Cette action est irréversible.")) {
      return;
