// --- Helper function to check if user is admin ---
// This function now expects the idToken to be passed in the data payload
const isAuthenticatedAdmin = async (data) => {
  const idToken = data.idToken;

  if (!idToken) {
    throw new functions.https.HttpsError('unauthenticated', 'Authentication token required.');
  }

  try {
    const decodedToken = await admin.auth().verifyIdToken(idToken);
    const uid = decodedToken.uid;

    const userDoc = await db.collection('users').doc(uid).get();
    if (!userDoc.exists) {
      throw new functions.https.HttpsError('not-found', 'User data not found for this token.');
    }
    const userData = userDoc.data();
    if (userData.role !== 'admin') {
      throw new functions.https.HttpsError('permission-denied', 'Only admin users can perform this action.');
    }
    return true;
  } catch (error) {
    if (error.code === 'auth/argument-error' || error.code === 'auth/id-token-expired' || error.code === 'auth/invalid-id-token') {
      throw new functions.https.HttpsError('unauthenticated', 'Authentication failed: Invalid or expired token.');
    }
    throw new functions.https.HttpsError('internal', 'Internal server error during authentication check.');
  }
};

